"use strict";(globalThis.webpackChunkall_maker=globalThis.webpackChunkall_maker||[]).push([[7053],{3328(e){e.exports=JSON.parse('{"permalink":"/blog/emotional-durability","source":"@site/blog/2026-03-03-emotional-durability.md","title":"Emotional durability in leadership","description":"Leadership is an exercise in endurance. Not physical\u2014emotional. You unify the vision, translate different perspectives into a single narrative, and you do not flinch when that narrative gets challenged. You know when to push and when to say no. That is the job.","date":"2026-03-03T00:00:00.000Z","tags":[{"inline":false,"label":"Technical Writing","permalink":"/blog/tags/technical-writing"},{"inline":false,"label":"Career","permalink":"/blog/tags/career"},{"inline":true,"label":"leadership","permalink":"/blog/tags/leadership"}],"readingTime":3,"hasTruncateMarker":false,"authors":[{"name":"Strahinja Milo\u0161evi\u0107","title":"Senior Technical Writer","url":"https://strahinjamilosevic.github.io/","page":{"permalink":"/blog/authors/strahinja"},"socials":{"linkedin":"https://www.linkedin.com/in/strahinjamilosevic/","github":"https://github.com/strahinjamilosevic"},"description":"Hi, I\'m Stra. A long time ago I studied English language and literature. I don\'t know if I see myself as a linguist, but studying language and literature has definitely shaped how I view the world.\\n\\nThere\'s a plethora of things that interest me. I think what defines me is that I just get up and try them out. \\"Jack of all trades, master of none...\\" kind of deal, yes.\\n\\nWhat do I see myself as? I don\'t know. I\'d probably say a dedicated father and husband. An avid music enjoyer, a disentangler of topics, and a vain old fart. ;)\\n\\nBut that\'s the point of the old saying: \\"...oftentimes better than a master of one.\\" In any case, definitely \u2014 a maker of sorts.\\n","imageURL":"/img/prof.jpg","key":"strahinja"}],"frontMatter":{"slug":"emotional-durability","title":"Emotional durability in leadership","authors":["strahinja"],"tags":["technical writing","career","leadership"]},"unlisted":false,"nextItem":{"title":"Tech writing career ladder","permalink":"/blog/career"}}')},7576(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>s,metadata:()=>a,toc:()=>h});var a=n(3328),i=n(4848),o=n(8453);const s={slug:"emotional-durability",title:"Emotional durability in leadership",authors:["strahinja"],tags:["technical writing","career","leadership"]},r=void 0,l={authorsImageUrls:[void 0]},h=[];function d(e){const t={p:"p",...(0,o.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.p,{children:"Leadership is an exercise in endurance. Not physical\u2014emotional. You unify the vision, translate different perspectives into a single narrative, and you do not flinch when that narrative gets challenged. You know when to push and when to say no. That is the job."}),"\n",(0,i.jsx)(t.p,{children:"I used to think that this meant that my manager was being a smartass. Asking me if I had spoken to person a, b, or c? And I always answered that, of course, I had. I knew what I was doing. Until it happened that I did not because I lacked the context. That moment stayed with me."}),"\n",(0,i.jsx)(t.p,{children:"This happens all the time at organizations of low level of maturity. Everybody's crazy smart and capable. Tons of experience. Chances are that they all have a track record of impressive accomplishments."}),"\n",(0,i.jsx)(t.p,{children:"Chances are that they also know this. And how to do the job. But here's something that I often see disregarded: emotional strength to do the necessary."}),"\n",(0,i.jsx)(t.p,{children:"You've heard it a thousand times: we need to plan better. We have a communication issue. The knowledge base is fragmented. There is no single source of truth. The decision making is made on the go and no one takes ownership."}),"\n",(0,i.jsx)(t.p,{children:"That's the crux. We all meet and make decisions on the fly. We even write them down. We even use the same tools and tickets."}),"\n",(0,i.jsx)(t.p,{children:"But the owners of the decisions get worn down. They have to explain the same decision over and over to different teams and in different contexts. And be ready for, even welcome, being challenged every step of the way."}),"\n",(0,i.jsx)(t.p,{children:"We all have opinions. Some are even experts at what they do. But a leader is supposed to contextualize, align, pick a fight, and see it through."}),"\n",(0,i.jsx)(t.p,{children:"Some get to these positions simply because it was next. And they fall short in trying to defend the product decision that's already been reviewed and made with due diligence."}),"\n",(0,i.jsx)(t.p,{children:"They give up. Decide that the stress is way above the pay grade and just start nodding."}),"\n",(0,i.jsx)(t.p,{children:"We've all seen it in practice. Decisions made in isolation, miscommunicated, each one reasonable on its own, but collectively exhausting.\nBusiness considers it an unfair advantage to certain customers. Change the offering. Management is fed up with the latest incidents \u2014 migrate away from CloudFlare to something more durable. Infrastructure recreates the pipeline \u2014 product does not like the port numbers. Change them again, same starting digit. Support is drowning. Nobody reacts."}),"\n",(0,i.jsx)(t.p,{children:"We do the work. And change it again. And again. And talk. Incessantly."}),"\n",(0,i.jsx)(t.p,{children:"The leadership proclaims: everybody's doing the best they can. But they can feel it. Everybody on edge. Not because they can't do their jobs. But because they have been forced to redo a simple task multiple times."}),"\n",(0,i.jsx)(t.p,{children:"Therein lies the rub. People need meaning. Motivation. I concede\u2014there are jobs and workers in the world where the bare minimum is enough."}),"\n",(0,i.jsx)(t.p,{children:"I also feel that in building software, product, and technology\u2014people are ambitious. They want to feel like they contribute. Like they build something that matters."}),"\n",(0,i.jsx)(t.p,{children:"This is why weak leadership kills teams and products. It's a slippery slope, the ladder, and a paradox in its own right."}),"\n",(0,i.jsx)(t.p,{children:"You climb the ladder. Become a leader. Find it emotionally taxing. Become agreeable and start nodding. The team does the same. And together you do a disservice to the company as well as yourself."}),"\n",(0,i.jsx)(t.p,{children:"It's difficult to recognize whether you actually want it or you believed somebody that you should want it. But one thing is certain: emotional durability is not a soft skill. It is the job."})]})}function c(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var a=n(6540);const i={},o=a.createContext(i);function s(e){const t=a.useContext(o);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),a.createElement(o.Provider,{value:t},e.children)}}}]);